#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int a[n];
        int flag = 0;
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
            if (a[i] == 1) {
                flag = 1;
            }
        }
        if (flag == 1) {
            printf("Easy\n");
        } else {
            printf("Hard\n");
        }
    }
    return 0;
}

