const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
    } else if (i % 2 == 1) {
        input.push(parseInt(line));
    } else {
        let a = line.split(' ').map(x => parseInt(x));
        input.push(a);
        if (i / 2 == t) {
            readline.close();
        }
    }
    i++;
});
readline.on('close', () => {
    for (let i = 0; i < t; i++) {
        let n = input[i * 2];
        let a = input[i * 2 + 1];
        if (a.includes(1)) {
            console.log("Easy");
        } else {
            console.log("Hard");
        }
    }
});
